input.new_string:
// ---------- scroll reveal ----------
// IntersectionObserverに依存せず、rectを直接見て判定する。
// 万一スクロール判定が働かない環境でもコンテンツが消えないよう、
// 一定時間後に必ず全要素を表示するフェイルセーフを併設。
const revealEls = [...document.querySelectorAll(".reveal-on-scroll")];
function checkReveal() {
  const vh = window.innerHeight || document.documentElement.clientHeight;
  for (const el of revealEls) {
    if (el.classList.contains("in")) continue;
    const r = el.getBoundingClientRect();
    if (r.top < vh * 0.9 && r.bottom > 0) el.classList.add("in");
  }
}
window.addEventListener("scroll", checkReveal, { passive: true });
window.addEventListener("resize", checkReveal, { passive: true });
window.addEventListener("load", checkReveal);
checkReveal();
// フェイルセーフ: 何が起きても1.4秒後には全て表示する
setTimeout(() => revealEls.forEach(el => el.classList.add("in")), 1400);

