(() => {
  const els = [...document.querySelectorAll('.reveal-on-scroll')];
  return JSON.stringify({
    classLists: els.map(e => e.className),
    // does the CSS rule exist / match?
    matchTest: (() => { const e = els[0]; e.classList.add('in'); const op = getComputedStyle(e).opacity; return op; })(),
    // check the raw stylesheet for the .js rule
    hasJsRule: [...document.styleSheets].some(ss => { try { return [...ss.cssRules].some(r => r.selectorText && r.selectorText.includes('.js .reveal-on-scroll.in')); } catch { return false; } })
  });
})()

(() => {
  const el = document.querySelectorAll('.reveal-on-scroll')[1]; // has had 'in' the whole time
  // enumerate ALL matching CSS rules and their opacity declarations, in order
  const matched = [];
  for (const ss of document.styleSheets) {
    let rules; try { rules = ss.cssRules; } catch { continue; }
    for (const r of rules) {
      if (r.style && r.selectorText) {
        try { if (el.matches(r.selectorText) && r.style.opacity !== '') matched.push(r.selectorText + ' => opacity:' + r.style.opacity); } catch {}
      }
      // also check media rules
      if (r.media) {
        for (const mr of (r.cssRules||[])) {
          if (mr.style && mr.selectorText && mr.style.opacity !== '') {
            try { if (el.matches(mr.selectorText)) matched.push('@media('+r.media.mediaText+') '+mr.selectorText+' => opacity:'+mr.style.opacity + (window.matchMedia(r.media.mediaText).matches?' [ACTIVE]':' [inactive]')); } catch {}
          }
        }
      }
    }
  }
  return JSON.stringify({
    className: el.className,
    computedOpacity: getComputedStyle(el).opacity,
    inlineOpacity: el.style.opacity || '(none)',
    matchedRules: matched
  }, null, 1);
})()

