function playReveal(){
  if (reduceMotion) return;
  const app = $("app");
  const items = app.querySelectorAll(".reveal");
  items.forEach((el, i) => el.style.setProperty("--i", i));
  app.classList.remove("revealed", "revealing");
  void app.offsetWidth;               // リフローで確実に初期状態から再生
  app.classList.add("revealing");
  clearTimeout(playReveal._t);
  playReveal._t = setTimeout(() => app.classList.add("revealed"), 1100);  // フェイルセーフ
}

