$("cfgSave").addEventListener("click", () => {
  const url = $("cfgUrl").value.trim().replace(/\/+$/, "");
  const key = $("cfgKey").value.trim();
  if (!/^https:\/\/.+\.supabase\.co$/.test(url)) { setMsg("cfgMsg", "URLは https://xxxx.supabase.co の形式で入力してください。", true); return; }
  if (key.length < 30) { setMsg("cfgMsg", "anon key が短すぎます。Project Settings → API から正しくコピーしてください。", true); return; }
  localStorage.setItem(CFG_URL, url); localStorage.setItem(CFG_KEY, key);
  clearMsg("cfgMsg"); boot();
});
$("cfgLocal").addEventListener("click", startLocal);
$("reconfig").addEventListener("click", () => {
  localStorage.removeItem(CFG_URL); localStorage.removeItem(CFG_KEY);
  if (sb) { try { sb.auth.signOut(); } catch {} }
  sb = null; user = null; show("setupGate");
});

function startLocal(){
  store = Local; user = null; sb = null;
  $("whoami").innerHTML = 'この端末のみ（未登録） <b></b>';
  $("logoutBtn").textContent = "接続設定へ";
  $("footNote").innerHTML = "この端末（localStorage）にのみ保管中。端末を替える前に「JSONで封じる」で写しを取ってください。";

