641	  function animateGrand(to){
642	    const el = $("sumDiff"); const unit = '<span class="unit">枚</span>';
643	    if (reduceMotion || !firstPaint) { el.innerHTML = fmtSigned(to) + unit; return; }
644	    const dur = 900, t0 = performance.now();
645	    const settle = () => { el.innerHTML = fmtSigned(to) + unit; };
646	    (function step(now){
647	      const p = Math.min(1, (now - t0) / dur);
648	      el.innerHTML = fmtSigned(Math.round(to * (1 - Math.pow(1 - p, 3)))) + unit;
649	      if (p < 1) requestAnimationFrame(step); else settle();
650	    })(t0);
651	    setTimeout(settle, dur + 120);
652	  }
