767	    const rec = { date:$("fDate").value, diff:parseInt($("fDiff").value)||0, games:parseInt($("fGames").value)||0, bitaTry, bitaHit, setting:$("fSetting").value, memo:$("fMemo").value.trim() };
768	    const btn = $("submitBtn"); btn.disabled = true;
769	    try {
770	      if (editId !== null){ await store.update(editId, rec); toast("書き改めました"); exitEdit(); }
771	      else { await store.add(rec); toast("帳簿に記しました"); }
772	      firstPaint = false; renderAll();
773	      $("recordForm").reset(); $("fDate").value = localToday();
774	    } catch (err){ toast("保存失敗: " + err.message, true); }
775	    finally { btn.disabled = false; }
776	  });
777	
778	  function enterEdit(id){
779	    const r = records.find(r=>String(r.id)===String(id)); if(!r) return;
780	    editId = r.id;
781	    $("fDate").value=r.date; $("fDiff").value=r.diff; $("fGames").value=r.games||"";
782	    $("fBitaTry").value=r.bitaTry||""; $("fBitaHit").value=r.bitaHit||"";
783	    $("fSetting").value=r.setting||""; $("fMemo").value=r.memo||"";
784	    $("formTitle").textContent="記録を直す"; $("submitBtn").textContent="書き改める"; $("cancelEditBtn").style.display="inline-block";
785	    $("recordForm").scrollIntoView({ behavior: reduceMotion?"auto":"smooth", block:"center" });
786	  }
787	  function exitEdit(){ editId=null; $("formTitle").textContent="実戦を記入する"; $("submitBtn").textContent="帳簿に記す"; $("cancelEditBtn").style.display="none"; }
788	  $("cancelEditBtn").addEventListener("click", () => { exitEdit(); $("recordForm").reset(); $("fDate").value=localToday(); });
789	
790	  $("historyBody").addEventListener("click", async (e) => {
791	    const b = e.target.closest("button"); if(!b) return;
792	    if (b.dataset.edit) enterEdit(b.dataset.edit);
793	    if (b.dataset.del){
794	      const r = records.find(r=>String(r.id)===String(b.dataset.del)); if(!r) return;
795	      if (!confirm(`${r.date}（差枚 ${fmtSigned(r.diff)}）の記録を消すか。`)) return;
796	      try { await store.remove(r.id); if (String(editId)===String(r.id)){ exitEdit(); $("recordForm").reset(); } renderAll(); toast("消しました"); }
797	      catch (err){ toast("削除失敗: " + err.message, true); }
798	    }
799	  });
800	
801	  document.querySelector(".chart-tabs").addEventListener("click", (e) => {
802	    const b = e.target.closest("button"); if(!b) return;
803	    currentChart = b.dataset.chart;
