805	    renderChart();
806	  });
807	
808	  // ───────── 書き出し・読み込み ─────────
809	  function download(name, text, mime){ const blob=new Blob([text],{type:mime}); const a=document.createElement("a"); a.href=URL.createObjectURL(blob); a.download=name; a.click(); URL.revokeObjectURL(a.href); }
810	  $("exportCsvBtn").addEventListener("click", () => {
811	    const head="日付,差枚,回転数,ビタ試行,ビタ成功,推測設定,覚書";
