821	      try {
822	        const data=JSON.parse(rd.result);
823	        if(!Array.isArray(data)) throw new Error("形式が不正です");
824	        if(!confirm(`${data.length}件を読み込みます。${store===Cloud?"クラウドへ追加します。":"今の記録は置き換わります。"}`)) return;
