/* 押下フィードバック & タップ遅延解消 */
button, .cal-cell, a { touch-action:manipulation; }
.btn-primary:active, .btn-ghost:active, .btn-quiet:active, .cal-nav button:active, .chart-tabs button:active, .row-actions button:active { transform:scale(.97); }
.cal-cell:not(.blank):active { background:rgba(184,147,74,.24); }

/* 総差枚＝赤き真実の"宣告"に専用の入場を与える（画一的な一斉フェードを避ける） */
@keyframes truthDeclare { from { opacity:0; transform:translateY(14px) scale(.965); } to { opacity:1; transform:none; } }
.js #app.revealing .truth.reveal { animation:truthDeclare .85s cubic-bezier(.2,.7,.3,1) forwards; animation-delay:.12s; }

/* ローディング幕（クラウド読込中） */
.loading-veil { position:fixed; inset:0; z-index:200; display:flex; flex-direction:column; align-items:center; justify-content:center; gap:18px;
  background:rgba(13,10,13,.86); color:var(--gold-lit); font-family:var(--jp); letter-spacing:.25em; font-size:13px; }
.loading-veil .spin { animation:spin 2.4s linear infinite; }
@media (prefers-reduced-motion:reduce){ .loading-veil .spin { animation:none; } }

/* チャートの空状態 */
.chart-empty { display:none; position:absolute; inset:0; align-items:center; justify-content:center; text-align:center; padding:0 20px;
  font-family:var(--serif); font-style:italic; font-size:15px; color:var(--ash); }
.chart-empty.show { display:flex; }

[hidden] { display:none !important; }
@media (prefers-reduced-motion:reduce){ .sheet{ animation:none; opacity:1; } }

